const data = $input.first().json;
const msg = data.message.toLowerCase();
let category = 'product_question';
let urgency = 'low';
let product = null;
let orderId = null;
let summary = 'General inquiry';

const products = ['sf2 driver','sf1 driver','sf1','sf2','357','359','one.1','click stick','sq putter','square set','drawforce','hinge','launch deck','pg1'];
for (const p of products) { if (msg.includes(p)) { product = p; break; } }
const orderMatch = data.message.match(/(?:order|#|T-)\s*([A-Z0-9-]+)/i);
if (orderMatch) orderId = orderMatch[1];

if (msg.includes('refund') || msg.includes('return') || msg.includes('money back')) {
  category = 'refund'; urgency = 'medium'; summary = 'Customer requesting refund/return';
} else if (msg.includes('broken') || msg.includes('damaged') || msg.includes('crushed')) {
  category = 'shipping'; urgency = 'high'; summary = 'Product damaged in shipping';
} else if (msg.includes('charge') || msg.includes('subscription') || msg.includes('unauthorized') || msg.includes('credit card')) {
  category = 'billing_dispute'; urgency = 'high'; summary = 'Billing dispute - possible unauthorized charge';
} else if (msg.includes('vip') || msg.includes('golf school')) {
  category = 'vip_coaching'; urgency = 'low'; product = 'VIP Golf School'; summary = 'VIP Golf School inquiry';
} else if (msg.includes('app') || msg.includes('crash') || msg.includes('white screen')) {
  category = 'technical_support'; urgency = 'medium'; product = 'Mobile App'; summary = 'App technical issue';
}

return [{ json: { ...data, classification: { category, urgency, product_mentioned: product, order_id: orderId, summary } } }];
